#!/usr/bin/env python3 """ skill_benchmark.py Skill Evolution Benchmark Harness Runs deterministic micro-benchmarks across skill domains. Stores results as JSONL for trend tracking. Usage: python skill_benchmark.py --all python skill_benchmark.py --skill vault-curation python skill_benchmark.py --skill vault-curation --baseline python skill_benchmark.py --trend --domain vault-curation """ import argparse import json import os import sys import time import traceback from datetime import datetime, timezone from pathlib import Path # Paths SCRIPT_DIR = Path(__file__).resolve().parent HERMESDATA = SCRIPT_DIR.parent BENCH_DATA = HERMESDATA / "skill_evo" / "benchmarks" LOG_DIR = HERMESDATA / "skill_evo" / "logs" SNAPSHOT_DIR = HERMESDATA / "skill_evo" / "snapshots" for p in [BENCH_DATA, LOG_DIR, SNAPSHOT_DIR]: p.mkdir(parents=True, exist_ok=True) BENCH_TS = datetime.now(timezone.utc).strftime("%Y%m%d_%H%M%S") RESULTS_FILE = BENCH_DATA / f"bench_{BENCH_TS}.jsonl" TREND_FILE = BENCH_DATA / "trends.jsonl" # # Benchmark Task Definitions # Each task: {id, skill, domain, description, fn, max_seconds} # fn() -> dict with keys: passed (bool), score (0-1), notes (str) # def bench_skill_file_exists(): """Verify all installed skills have SKILL.md (skip category grouping dirs)""" skills_dir = HERMESDATA / "skills" total = 0 passed = 0 missing = [] for skill_path in sorted(skills_dir.iterdir()): if not skill_path.is_dir(): continue # Skip empty/curator backup dirs if skill_path.name.startswith(".") or skill_path.name == ".curator_backups": continue skill_md = skill_path / "SKILL.md" # A valid skill either has a SKILL.md directly, or it's a category # grouping directory whose children are actual skills. has_direct_skill = skill_md.exists() and skill_md.stat().st_size > 100 # Check if it's a category dir (contains subdirs with SKILL.md) children_with_skills = any( (skill_path / sub / "SKILL.md").exists() for sub in skill_path.iterdir() if sub.is_dir() and not sub.name.startswith(".") ) if has_direct_skill: total += 1 passed += 1 elif children_with_skills: # Category grouping dir count as valid structure total += 1 passed += 1 else: total += 1 missing.append(skill_path.name) return { "passed": passed == total, "score": passed / total if total else 0, "notes": f"{passed}/{total} skills have valid SKILL.md", "missing": missing[:10], } def bench_vault_lint(): """Check vault bidirectional link integrity (sample)""" vault = Path(r"D:\PhronesisVault") if not vault.exists(): return {"passed": False, "score": 0, "notes": "Vault not found"} md_files = list(vault.rglob("*.md")) total = len(md_files) if total == 0: return {"passed": False, "score": 0, "notes": "No .md files in vault"} # Check for broken [[links]] link target exists broken = 0 checked = 0 for md_file in md_files[:50]: # sample first 50 try: content = md_file.read_text(encoding="utf-8", errors="ignore") links = [l.strip() for l in content.split("[[")[1:] if "]]" in l] for link in links[:5]: checked += 1 # Resolve relative to vault root target = vault / link.split("]]")[0].strip() if not target.exists(): # Try with .md extension if not (target.with_suffix(".md")).exists(): broken += 1 except Exception: pass score = (checked - broken) / checked if checked else 1.0 return { "passed": broken == 0, "score": score, "notes": f"Checked {checked} links, {broken} broken (sample of {total} files)", } def bench_git_backup(): """Verify git is operational in key repos""" repos = [ HERMESDATA, Path(r"D:\PhronesisVault"), ] results = [] for repo in repos: if not (repo / ".git").exists(): results.append({"repo": str(repo), "status": "no-git"}) else: results.append({"repo": str(repo), "status": "has-git"}) has_git = sum(1 for r in results if r["status"] == "has-git") return { "passed": has_git == len(repos), "score": has_git / len(repos), "notes": f"{has_git}/{len(repos)} repos have git", "details": results, } def bench_skill_evo_infra(): """Verify skill_evo infrastructure exists""" checks = { "snapshots_dir": SNAPSHOT_DIR.exists(), "benchmarks_dir": BENCH_DATA.exists(), "logs_dir": LOG_DIR.exists(), } passed = sum(1 for v in checks.values() if v) total = len(checks) return { "passed": passed == total, "score": passed / total, "notes": f"{passed}/{total} infra dirs exist", "checks": checks, } def bench_hermes_config(): """Verify Hermes config is accessible""" config_paths = [ HERMESDATA / "config.yaml", Path.home() / ".hermes" / "config.yaml", ] found = any(p.exists() for p in config_paths) return { "passed": found, "score": 1.0 if found else 0.0, "notes": f"Config found: {found}", } def bench_script_execution(): """Verify existing scripts can be imported/executed""" test_scripts = [ SCRIPT_DIR / "classify_ingest.py", SCRIPT_DIR / "daily-vault-hygiene.py", ] results = [] for script in test_scripts: if not script.exists(): results.append({"script": script.name, "status": "missing"}) continue try: # Just check syntax via compile compile(script.read_text(encoding="utf-8", errors="ignore"), str(script), "exec") results.append({"script": script.name, "status": "syntax-ok"}) except SyntaxError as e: results.append({"script": script.name, "status": f"syntax-error: {e}"}) ok = sum(1 for r in results if r["status"] == "syntax-ok") return { "passed": ok == len(results), "score": ok / len(results) if results else 1.0, "notes": f"{ok}/{len(results)} scripts pass syntax check", "details": results, } def bench_skill_content_quality(): """Measure whether skills have actionable content (not empty stubs). Structural checks: does the skill have the expected sections? This is the original benchmark kept for trend continuity. """ skills_dir = HERMESDATA / "skills" total = 0 passing = 0 issues = [] for skill_path in sorted(skills_dir.iterdir()): if not skill_path.is_dir(): continue if skill_path.name.startswith("."): continue skill_md = skill_path / "SKILL.md" if not skill_md.exists() or skill_md.stat().st_size < 100: continue total += 1 content = skill_md.read_text(encoding="utf-8", errors="ignore") # Quality heuristics (inspired by SkillOpt's validation gate) has_yaml_frontmatter = content.startswith("---") has_purpose_section = any(kw in content.lower() for kw in ["**purpose**:", "## purpose", "# purpose"]) has_steps = any(kw in content for kw in ["## core functions", "## when ", "## algorithm", "## key ", "## integration"]) has_over_50_lines = len(content.split("\n")) > 50 has_references_section = "## references" in content.lower() or "## see also" in content.lower() score_items = [has_yaml_frontmatter, has_purpose_section, has_steps, has_over_50_lines, has_references_section] skill_score = sum(1 for s in score_items if s) / len(score_items) if skill_score >= 0.6: # at least 3/5 quality signals passing += 1 else: issues.append({ "skill": skill_path.name, "score": round(skill_score, 2), "missing": [ k for k, v in zip( ["frontmatter", "purpose", "steps", "depth", "references"], score_items ) if not v ], }) return { "passed": passing == total, "score": passing / total if total else 0, "notes": f"{passing}/{total} skills pass quality gate (3/5 signals)", "issues": issues[:5], } def bench_skill_actionability(): """Measure information density does the skill contain concrete actionable content? Unlike skill_content_quality (structural), this measures: - Code blocks with actual commands (not just ``` markers) - Specific tool invocations with parameters - Numbered procedural steps with concrete actions - File paths, configuration snippets, error handling patterns The key distinction: a skill that says "Use cronjob to schedule things" is weaker than one that says "cronjob action=create schedule='0 */6 * * *' prompt='...'" """ skills_dir = HERMESDATA / "skills" total = 0 passing = 0 scores = {} for skill_path in sorted(skills_dir.iterdir()): if not skill_path.is_dir(): continue if skill_path.name.startswith("."): continue skill_md = skill_path / "SKILL.md" if not skill_md.exists() or skill_md.stat().st_size < 100: continue total += 1 content = skill_md.read_text(encoding="utf-8", errors="ignore") lines = content.split("\n") total_lines = len(lines) if total_lines == 0: scores[skill_path.name] = 0.0 continue # Count truly actionable lines must be SPECIFIC, not generic actionable = 0 in_code_block = False code_block_content_lines = 0 for line in lines: stripped = line.strip() # Code block markers count the block as actionable only if it has content if stripped.startswith("```"): if in_code_block: # End of code block count it if it had content if code_block_content_lines > 0: actionable += 1 # count the whole block as 1 actionable unit code_block_content_lines = 0 in_code_block = not in_code_block continue if in_code_block: if stripped and not stripped.startswith("#") and not stripped.startswith("//"): code_block_content_lines += 1 continue # Lines with actual tool call patterns (function-like syntax) # e.g., "cronjob(action='create', ...)" or "skill_manage(action='patch', ...)" if "(" in stripped and ")" in stripped: func_names = [ "cronjob(", "skill_manage(", "skill_view(", "skill_benchmark(", "skill_genome(", "terminal(", "write_file(", "read_file(", "patch(", "search_files(", "web_search(", "web_extract(", "delegate_task(", "image_generate(", "text_to_speech(", ] if any(fn in stripped for fn in func_names): actionable += 1 continue # Lines with specific CLI flags or paths (D:\..., /d/, --flag, etc) specific_patterns = [ "D:\\", "C:\\", "/d/", "--name", "--schedule", "--prompt", "--workdir", "--deliver", "--skill", "--action", "--model", "python ", "pip install", "pytest ", "py_compile", "curl ", "wget ", "git add", "git commit", "git push", "hermes ", "obsidian://", "discord:", "telegram:", ] if any(p in stripped for p in specific_patterns): actionable += 1 continue # Numbered steps with VERBS (action-oriented, not just "1. Introduction") if len(stripped) > 3 and stripped[0].isdigit() and stripped[1] == ".": # Check if the line after the number contains an action verb after_num = stripped[2:].strip() action_verbs = [ "create", "run", "verify", "check", "install", "configure", "execute", "validate", "process", "generate", "update", "delete", "write", "read", "scan", "search", "find", "add", "remove", "set", "get", "list", "start", "stop", "enable", "disable", "convert", "transform", "extract", ] if any(after_num.lower().startswith(v) for v in action_verbs): actionable += 1 continue # Lines with error handling patterns (try/except, if error, on failure) if any(kw in stripped for kw in ["try:", "except ", "catch ", "on error", "on failure", "if error", "fallback"]): actionable += 1 continue # Actionability: ratio of actionable "units" to total lines # A dense skill has ~20%+ actionable content actionability_ratio = actionable / total_lines if total_lines else 0 # Score: 0 at 5% actionable, 1.0 at 25% actionable (capped) normalized_score = min(1.0, actionability_ratio / 0.25) scores[skill_path.name] = round(normalized_score, 3) if normalized_score >= 0.5: # at least 12.5% actionable lines passing += 1 # Find worst performers for improvement targeting sorted_scores = sorted(scores.items(), key=lambda x: x[1]) worst = [{"skill": s, "score": sc} for s, sc in sorted_scores[:10] if sc < 0.5] avg_score = sum(scores.values()) / len(scores) if scores else 0 return { "passed": passing == total, "score": passing / total if total else 0, "notes": f"{passing}/{total} skills pass actionability gate (50% score, avg={avg_score:.2f})", "avg_actionability": round(avg_score, 3), "worst_skills": worst, "details": {"scores": scores}, } # # Registry # BENCHMARKS = [ { "id": "skill_files_integrity", "skill": "infrastructure", "domain": "infrastructure", "description": "All installed skills have valid SKILL.md files", "fn": bench_skill_file_exists, "max_seconds": 30, }, { "id": "vault_link_integrity", "skill": "vault-curation", "domain": "vault", "description": "Vault bidirectional links resolve correctly", "fn": bench_vault_lint, "max_seconds": 60, }, { "id": "git_backup_status", "skill": "github-autobackup", "domain": "infrastructure", "description": "Git repositories are initialized for backup", "fn": bench_git_backup, "max_seconds": 10, }, { "id": "skill_evo_infra", "skill": "infrastructure", "domain": "infrastructure", "description": "skill_evo directories exist for evolution tracking", "fn": bench_skill_evo_infra, "max_seconds": 5, }, { "id": "hermes_config", "skill": "hermes-agent", "domain": "infrastructure", "description": "Hermes configuration is accessible", "fn": bench_hermes_config, "max_seconds": 5, }, { "id": "script_execution", "skill": "automated-testing", "domain": "infrastructure", "description": "Existing scripts pass syntax validation", "fn": bench_script_execution, "max_seconds": 10, }, { "id": "skill_content_quality", "skill": "skillforge", "domain": "infrastructure", "description": "Skills have actionable content (frontmatter, purpose, steps, depth, references)", "fn": bench_skill_content_quality, "max_seconds": 15, }, { "id": "skill_actionability", "skill": "skillforge", "domain": "quality", "description": "Skills contain concrete actionable content (code, commands, steps, tools)", "fn": bench_skill_actionability, "max_seconds": 15, }, ] def run_benchmark(bench_def): """Run a single benchmark, return result dict""" start = time.time() try: result = bench_def["fn"]() elapsed = time.time() - start return { "id": bench_def["id"], "skill": bench_def["skill"], "domain": bench_def["domain"], "description": bench_def["description"], "passed": result["passed"], "score": result["score"], "elapsed_s": round(elapsed, 3), "notes": result["notes"], "details": result, "timestamp": datetime.now(timezone.utc).isoformat(), "status": "ok", } except Exception as e: elapsed = time.time() - start return { "id": bench_def["id"], "skill": bench_def["skill"], "domain": bench_def["domain"], "description": bench_def["description"], "passed": False, "score": 0.0, "elapsed_s": round(elapsed, 3), "notes": f"ERROR: {e}", "details": {"traceback": traceback.format_exc()}, "timestamp": datetime.now(timezone.utc).isoformat(), "status": "error", } def run_all(skill_filter=None): """Run all or filtered benchmarks""" to_run = BENCHMARKS if skill_filter: to_run = [b for b in to_run if b["skill"] == skill_filter or b["domain"] == skill_filter] results = [] print(f"\n{'='*60}") print(f" SKILL EVOLUTION BENCHMARK {BENCH_TS}") print(f" Running {len(to_run)} tests") print(f"{'='*60}\n") for bench_def in to_run: result = run_benchmark(bench_def) results.append(result) status_icon = "PASS" if result["passed"] else "FAIL" score_pct = f"{result['score']*100:.0f}%" print(f" [{status_icon}] {result['id']:30s} {score_pct:>5s} ({result['elapsed_s']:.2f}s)") if not result["passed"]: print(f" {result['notes']}") # Summary total = len(results) passed = sum(1 for r in results if r["passed"]) avg_score = sum(r["score"] for r in results) / total if total else 0 print(f"\n{''*60}") print(f" RESULT: {passed}/{total} passed | avg score {avg_score*100:.1f}%") print(f"{''*60}\n") # Write results with open(RESULTS_FILE, "w", encoding="utf-8") as f: for r in results: f.write(json.dumps(r, ensure_ascii=False) + "\n") # Append to trend file with open(TREND_FILE, "a", encoding="utf-8") as f: summary = { "timestamp": datetime.now(timezone.utc).isoformat(), "bench_ts": BENCH_TS, "total": total, "passed": passed, "avg_score": round(avg_score, 4), "scores": {r["id"]: r["score"] for r in results}, } f.write(json.dumps(summary) + "\n") print(f" Results written to: {RESULTS_FILE}") print(f" Trend appended to: {TREND_FILE}") return results def show_trend(domain=None): """Show historical trend data""" if not TREND_FILE.exists(): print("No trend data yet. Run --all first.") return entries = [] with open(TREND_FILE, "r", encoding="utf-8") as f: for line in f: line = line.strip() if line: entries.append(json.loads(line)) if domain: entries = [e for e in entries if any( domain.lower() in sid.lower() for sid in e.get("scores", {}) )] if not entries: print(f"No trend data found for domain: {domain}") return print(f"\n{'='*60}") print(f" BENCHMARK TREND ({len(entries)} runs)") print(f"{'='*60}\n") for entry in entries[-10:]: # last 10 ts = entry["timestamp"][:19] print(f" {ts} {entry['passed']}/{entry['total']} passed avg={entry['avg_score']*100:.1f}%") if len(entries) >= 2: first = entries[0]["avg_score"] last = entries[-1]["avg_score"] delta = (last - first) * 100 direction = "IMPROVED" if delta > 0 else "REGRESSED" if delta < 0 else "STABLE" print(f"\n Delta: {delta:+.1f}pp ({direction})") print() def main(): parser = argparse.ArgumentParser(description="Skill Evolution Benchmark Harness") parser.add_argument("--all", action="store_true", help="Run all benchmarks") parser.add_argument("--skill", type=str, help="Filter by skill/domain name") parser.add_argument("--baseline", action="store_true", help="Record as baseline") parser.add_argument("--trend", action="store_true", help="Show trend data") parser.add_argument("--domain", type=str, help="Filter trend by domain") args = parser.parse_args() if args.trend: show_trend(args.domain) elif args.all or args.skill: results = run_all(args.skill) if args.baseline: baseline_file = BENCH_DATA / "baseline.json" with open(baseline_file, "w", encoding="utf-8") as f: json.dump({ "timestamp": datetime.now(timezone.utc).isoformat(), "results": results, "avg_score": sum(r["score"] for r in results) / len(results) if results else 0, }, f, indent=2) print(f" Baseline saved to: {baseline_file}") else: parser.print_help() if __name__ == "__main__": main()